code = """import json
import pandas as pd
import re

# Get business data from storage variable
business_data = locals()['var_functions.query_db:24']
print('Loaded', len(business_data), 'businesses')

# Process the data
credit_card_businesses = []
category_counts = {}

for business in business_data:
    business_id = business.get('business_id', '')
    attributes = business.get('attributes', {})
    
    # Check if attributes is valid and business accepts credit cards
    if attributes and isinstance(attributes, dict):
        if attributes.get('BusinessAcceptsCreditCards') == 'True':
            description = business.get('description', '')
            
            # Extract categories from description
            categories = []
            
            # Try different patterns to extract categories
            patterns = [
                r'services in ([^.]+)',  # Pattern: services in X, Y, and Z
                r'including ([^.]+)',    # Pattern: including X, Y, and Z
                r'category of [\'"]([^\'"]+)[\'"]'  # Pattern: category of 'X, Y'
            ]
            
            found = False
            for pattern in patterns:
                match = re.search(pattern, description)
                if match:
                    text = match.group(1).strip()
                    # Split by comma and 'and'
                    items = re.split(r',\s*|\ and\s', text)
                    for item in items:
                        item = item.strip().strip('.')
                        if item:
                            categories.append(item)
                    found = True
                    break
            
            # If no categories found, use Uncategorized
            if not categories:
                categories = ['Uncategorized']
            
            credit_card_businesses.append({
                'business_id': business_id,
                'categories': categories
            })
            
            # Count categories
            for category in categories:
                category_counts[category] = category_counts.get(category, 0) + 1

# Find category with most businesses
if category_counts:
    top_category = max(category_counts.items(), key=lambda x: x[1])
else:
    top_category = (None, 0)

result = {
    'total_businesses_checking': len(business_data),
    'credit_card_businesses': len(credit_card_businesses),
    'top_category': top_category,
    'category_counts_preview': sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:10]
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"""

